import { dashboardFor } from "../lib/store";
export default function Home() { const dashboard = dashboardFor("u-admin"); return <main><p className="eyebrow">Reference SaaS</p><h1>{dashboard.team.name}</h1><p>{dashboard.plan.name} plan · {dashboard.memberCount}/{dashboard.plan.seatLimit} seats</p><section><h2>Members</h2><ul>{dashboard.members.map((member) => <li key={member.id}>{member.name} <small>{member.role}</small></li>)}</ul></section><section><h2>Notifications</h2><ul>{dashboard.notifications.map((item) => <li key={item.id}>{item.message} <small>{item.status}</small></li>)}</ul></section></main>; }
